const DEFAULT_NON_HSI_EVP = 0.30;
const DEFAULT_HSI_MONTHLY_COGS_PCT = 0.75;
const DEFAULT_HSI_OTC_COGS_PCT = 0.25;

const GROUP_EVP = {
  "Komponen Astinet": 0.25,
  "PSB Astinet": 0.25,
  "Astinet Dedicated": 0.30,
  "Astinet BB": 0.30,
  "Astinet Fit IP/31": 0.30,
  "Astinet Fit IP/29": 0.20,
  "Astinet Lite": 0.30,
  "Astinet Premium": 0.30,
  "Astinet China Jabodetabek": 0.30,
  "Astinet China": 0.30,
  "Add On IPv4 Astinet": 0.50,
  "Astinet Reguler JaBoDeTaBek": 0.30,
  "Astinet Reguler Jawa": 0.30,
  "Astinet Beda BW JaBoDeTaBek": 0.30,
  "Astinet Fit": 0.30,
  "IP Transit Reguler Jabodetabek Global": 0.20,
  "IP Transit Beda BW Jabodetabek Domestik": 0.20,
  "IP Transit Beda BW Jabodetabek Global": 0.20,
  "IP Transit NeuCentrIX Reguler Jabodetabek": 0.20,
  "IP Transit NeuCentrIX Beda BW Jabodetabek Global": 0.20,
  "IP Transit NeuCentrIX Beda BW Jabodetabek Domestik": 0.20,
  "Metro-E Inner,Intra Jabodetabek P2P/P2MP - Best Effort": 0.30,
  "Metro-E Inner,Intra Jabodetabek P2P/P2MP - Interaktif": 0.30,
  "Metro-E Inner,Intra Jabodetabek MP2MP - Best Effort": 0.30,
  "Metro-E NeuCentIX Inter Pamal P2P/P2MP - Interaktif": 0.30,
  "Metro-E NeuCentIX NNI Pamal P2P/P2MP - Best Effort": 0.30,
  "Metro-E NeuCentIX NNI Pamal P2P/P2MP - Interaktif": 0.30,
  "VPN IP": 0.30,
  "Metro E": 0.30,
  "WMS": 0.30,
};

const PARENT_EVP = [
  ["PSB Astinet", 0.25],
  ["Astinet Fit IP/29", 0.20],
  ["Astinet Fit IP/31", 0.30],
  ["Add On IPv4 Astinet", 0.50],
  ["IP Transit", 0.20],
  ["VPN IP", 0.30],
  ["Metro E", 0.30],
  ["WMS", 0.30],
  ["Astinet", 0.30],
];

const normalizeEvp = (evp) => {
  if (evp == null || Number.isNaN(Number(evp))) return null;
  const value = Number(evp);
  if (value < 0) return null;
  return value > 1 ? value / 100 : value;
};

const normalizePct = (value) => {
  if (value == null || value === "" || Number.isNaN(Number(value))) return null;
  const normalized = Number(value);
  if (normalized < 0) return null;
  return normalized > 1 ? normalized / 100 : normalized;
};

const normalizeMoney = (value) => {
  if (value == null || value === "" || Number.isNaN(Number(value))) return 0;
  return Math.max(0, Number(value));
};

const resolveParentEvp = (product) => {
  const name = product?.value || "";
  const group = product?.group || "";
  for (const [prefix, evp] of PARENT_EVP) {
    if (name.startsWith(prefix) || group.startsWith(prefix) || name.includes(prefix) || group.includes(prefix)) {
      return evp;
    }
  }
  return null;
};

const resolveChargeType = (product) => {
  const explicit = `${product.info ?? product.chargeType ?? ""}`.trim();
  if (explicit) return explicit;

  const hasMonthly = normalizeMoney(product.bulanan) > 0;
  const hasOtc = normalizeMoney(product.otc) > 0;

  if (hasMonthly && hasOtc) return "MRC + OTC";
  if (hasOtc) return "OTC";
  return "MRC";
};

const resolveIsHSI = (product) => {
  if (typeof product.isHSI === "boolean") return product.isHSI;

  const name = `${product.value || ""}`.toUpperCase();
  const group = `${product.group || ""}`.toUpperCase();
  return (
    name.startsWith("HSI")
    || group.startsWith("HSI")
    || name.includes("PIJAR SEKOLAH")
    || group.includes("PIJAR SEKOLAH")
  );
};

const resolveMonthlyCogsPct = (product, evp, isHSI) => {
  const explicit = normalizePct(
    product.cogsBulananPct
    ?? product.monthlyCogsPct
    ?? product.cogsRecurringPct
    ?? product.cogsPctBulanan
  );
  if (explicit != null) return explicit;
  if (isHSI) return DEFAULT_HSI_MONTHLY_COGS_PCT;
  if (evp != null) return Math.max(0, 1 - evp);
  return null;
};

const resolveMonthlyCogsNominal = (product) => normalizeMoney(
  product.cogsBulananNominal
  ?? product.monthlyCogsNominal
  ?? product.cogsRecurringNominal
  ?? product.cogsNominalBulanan
);

const resolveOtcCogsPct = (product, isHSI) => {
  const explicit = normalizePct(
    product.cogsOtcPct
    ?? product.otcCogsPct
    ?? product.cogsPsbPct
    ?? product.cogsPctOtc
  );
  if (explicit != null) return explicit;
  if (normalizeMoney(product.otc) <= 0) return 0;
  return isHSI ? DEFAULT_HSI_OTC_COGS_PCT : 0.75;
};

const resolveOtcCogsNominal = (product) => normalizeMoney(
  product.cogsOtcNominal
  ?? product.otcCogsNominal
  ?? product.cogsPsbNominal
  ?? product.cogsNominalOtc
);

export const PRODUCTS = RAW_PRODUCTS.map((product) => {
  const isHSI = resolveIsHSI(product);
  const explicitEvp = normalizeEvp(product.evp);
  const parentEvp = normalizeEvp(resolveParentEvp(product));
  const groupEvp = normalizeEvp(GROUP_EVP[product.group]);
  const evp = isHSI
    ? null
    : (explicitEvp ?? parentEvp ?? groupEvp ?? DEFAULT_NON_HSI_EVP);
  const info = resolveChargeType(product);

  return {
    ...product,
    isHSI,
    evp,
    info,
    chargeType: info,
    cogsBulananPct: resolveMonthlyCogsPct(product, evp, isHSI),
    cogsBulananNominal: resolveMonthlyCogsNominal(product),
    cogsOtcPct: resolveOtcCogsPct(product, isHSI),
    cogsOtcNominal: resolveOtcCogsNominal(product),
  };
});

